insert into public.products (name, slug, description, category, gender, price, original_price, images, fabric, sizes, colors, in_stock, stock_qty, low_stock_threshold, is_new, is_bestseller, season, occasion, style, tailoring_notes, delivery_estimate, rating, review_count)
values
('The Executive Tailored Blazer', 'executive-tailored-blazer', 'A masterfully constructed single-breasted blazer cut from Italian wool blend. Features notched lapels, structured shoulders, and flap pockets.', 'Bespoke', 'men', 850000, 950000, ARRAY['https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=600&q=80', 'https://images.unsplash.com/photo-1593030761757-71fae45fa0e7?w=600&q=80'], 'Italian Wool Blend', ARRAY['38', '40', '42', '44', '46'], ARRAY['Charcoal', 'Navy', 'Black'], true, 15, 5, true, true, 'All Season', 'Corporate', 'Classic', 'Fully canvassed construction with hand-stitched lapels and horn buttons.', '7-14 business days', 4.8, 24),
('The Opulent Evening Gown', 'opulent-evening-gown', 'An enchanting floor-length gown in silk crepe de Chine. Features a plunging V-neck, open back, and a sweeping train.', 'Evening Wear', 'women', 1200000, 1500000, ARRAY['https://images.unsplash.com/photo-1566174053879-31528523f8ae?w=600&q=80', 'https://images.unsplash.com/photo-1572804013309-59a88b7e92f1?w=600&q=80'], 'Silk Crepe de Chine', ARRAY['XS', 'S', 'M', 'L', 'XL'], ARRAY['Midnight Blue', 'Burgundy', 'Emerald'], true, 8, 3, true, true, 'Fall/Winter', 'Evening', 'Editorial', 'Hand-beaded bodice with French seam finishing.', '14-21 business days', 4.9, 31),
('The Couture Tuxedo', 'couture-tuxedo', 'The pinnacle of formalwear. Crafted from Super 120s wool with satin peak lapels, this tuxedo redefines black-tie elegance.', 'Bespoke', 'men', 1800000, 2200000, ARRAY['https://images.unsplash.com/photo-1594938298603-c8148c4dae35?w=600&q=80', 'https://images.unsplash.com/photo-1593030761757-71fae45fa0e7?w=600&q=80'], 'Super 120s Wool', ARRAY['38', '40', '42', '44', '46'], ARRAY['Black', 'Midnight Blue'], true, 5, 2, false, true, 'All Season', 'Wedding', 'Classic', 'Silk satin lapels with hand-bound buttonholes and grosgrain trim.', '14-21 business days', 5.0, 18),
('The Aso Oke Bridal Corset', 'aso-oke-bridal-corset', 'A breathtaking corset top handcrafted from French lace and handwoven Aso Oke. Features a sweetheart neckline and boned structure.', 'Wedding', 'women', 950000, 1100000, ARRAY['https://images.unsplash.com/photo-1515372039744-b8f02a3ae446?w=600&q=80', 'https://images.unsplash.com/photo-1559551409-dadc959f76b8?w=600&q=80'], 'French Lace & Silk', ARRAY['XS', 'S', 'M', 'L', 'XL'], ARRAY['Ivory', 'Champagne', 'Blush'], true, 6, 2, true, false, 'Spring/Summer', 'Wedding', 'Romantic', 'Hand-beaded French lace overlay with silk organza underlay.', '21-28 business days', 4.7, 15),
('The Lagos Luxe Kaftan', 'lagos-luxe-kaftan', 'A reimagined classic. Flowing silk crepe kaftan with hand-embroidered neckline and side slits. Effortless luxury.', 'Traditional Wear', 'women', 650000, 780000, ARRAY['https://images.unsplash.com/photo-1539008835657-9e8e9680c956?w=600&q=80'], 'Silk Crepe de Chine', ARRAY['S', 'M', 'L', 'XL', 'XXL'], ARRAY['Gold', 'Emerald', 'Royal Blue'], true, 12, 3, true, true, 'All Season', 'Casual', 'Modern Classic', 'Hand-embroidered Swarovski crystal detailing at neckline.', '7-14 business days', 4.6, 22),
('The Precision Tailored Trousers', 'precision-tailored-trousers', 'Sharp, modern trousers in premium Italian wool. Flat front with side adjusters and a tapered leg.', 'Ready-to-Wear', 'men', 350000, 420000, ARRAY['https://images.unsplash.com/photo-1594938298603-c8148c4dae35?w=600&q=80'], 'Italian Wool', ARRAY['28', '30', '32', '34', '36', '38', '40', '42'], ARRAY['Charcoal', 'Navy', 'Beige'], true, 25, 5, false, false, 'All Season', 'Corporate', 'Classic', 'Horn button adjusters with zip fly and internal waistband stabilization.', '5-10 business days', 4.5, 30),
('The Velvet Smoking Jacket', 'velvet-smoking-jacket', 'Luxurious silk velvet smoking jacket with shawl collar and contrast satin lapels. The ultimate host piece.', 'Luxury Evening Wear', 'men', 1350000, 1600000, ARRAY['https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=600&q=80'], 'Silk Velvet', ARRAY['38', '40', '42', '44', '46'], ARRAY['Burgundy', 'Forest Green', 'Midnight Blue'], true, 7, 2, false, true, 'Fall/Winter', 'Evening', 'Luxury', 'Silk satin lapels with quilted lining and jetted pockets.', '14-21 business days', 4.9, 12),
('The Cashmere Overcoat', 'cashmere-overcoat', 'An investment piece for the discerning gentleman. Double-breasted overcoat in pure Mongolian cashmere.', 'Casual Essentials', 'men', 2200000, 2800000, ARRAY['https://images.unsplash.com/photo-1544022613-e87ca75a784a?w=600&q=80'], 'Mongolian Cashmere', ARRAY['38', '40', '42', '44', '46'], ARRAY['Camel', 'Charcoal', 'Black'], true, 4, 2, true, false, 'Fall/Winter', 'Casual', 'Contemporary Heritage', 'Double-breasted with half-canvas construction and horn toggle buttons.', '14-21 business days', 5.0, 9),
('The Leather Weekender', 'leather-weekender', 'Handcrafted full-grain Italian leather duffle bag with brass hardware and detachable shoulder strap. Ages beautifully.', 'Accessories', 'unisex', 750000, 850000, ARRAY['https://images.unsplash.com/photo-1553062407-98eeb64c6a62?w=600&q=80'], 'Full-Grain Italian Leather', ARRAY['One Size'], ARRAY['Tan', 'Black', 'Brown'], true, 10, 3, false, false, 'All Season', 'Casual', 'Minimalist', 'Brass YKK zippers with leather pull tags and canvas lining.', '7-14 business days', 4.7, 20),
('The Relaxed Linen Suit', 'relaxed-linen-suit', 'Unconstructed linen suit in a relaxed silhouette. Perfect for the modern creative. Jacket and trousers set.', 'Ready-to-Wear', 'unisex', 550000, 680000, ARRAY['https://images.unsplash.com/photo-1593030761757-71fae45fa0e7?w=600&q=80', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=600&q=80'], 'Premium Linen', ARRAY['S', 'M', 'L', 'XL', 'XXL'], ARRAY['Ecru', 'Slate', 'Sage'], true, 18, 5, false, false, 'Spring/Summer', 'Corporate', 'Relaxed', 'Unstructured construction with natural shoulder and patch pockets.', '7-14 business days', 4.4, 16)
